module.exports={"chapter":{"id":"sg-ch05","exam":"sg","sourceId":"sg_security_textbook","order":5,"titleJa":"第5章 法務","titleZh":"第5章 法务"},"units":[{"id":"sg-5-1-1","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":1,"nativeSectionId":"5-1-1","titleJa":"5-1-1 サイバーセキュリティ基本法","titleZh":"5-1-1 日本网络安全基本法基本框架","overviewJa":"サイバーセキュリティ基本法は、SG法務分野でサイバーセキュリティ基本法は、国、地方公共団体、重要社会基盤事業者、サイバー関連事業者などの基本的責務を示します。個別の攻撃手口ではなく、社会全体でサイバーセキュリティを推進する枠組みとして読みます。PDF 264-265ページの「サイバーセキュリティ基本法」を定位語に、試験では「基本理念」「国の責務」「地方公共団体」「重要社会基盤」「事業者」が判断線です。不正アクセス禁止法や個人情報保護法との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"网络安全基本法用于理解国家、地方公共团体、重要基础设施和企业在网络安全中的基本责任。本单元依据 PDF 264-265 页的「ー基本法」定位，重点理解：网络安全基本法规定国家、地方公共团体、重要基础设施运营者和相关企业的基本责任。它不是单个攻击手法，而是社会整体推进网络安全的框架。考试常用基本理念、国家责任、地方公共团体、重要基础设施、事业者是判断词来换说法；同时要和非法访问禁止法或个人信息保护法区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「サイバーセキュリティ基本法」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“5-1-1 日本网络安全基本法基本框架”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"サイバーセキュリティ基本法を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。サイバーセキュリティ基本法は、国、地方公共団体、重要社会基盤事業者、サイバー関連事業者などの基本的責務を示します。個別の攻撃手口ではなく、社会全体でサイバーセキュリティを推進する枠組みとして読みます。この関係を押さえると、サイバーセキュリティ基本法は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではCybersecurity Basic Act、Critical Infrastructure、Responsibilityが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“日本网络安全基本法基本框架”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Cybersecurity Basic Act","Critical Infrastructure","Responsibility"],"examFocusJa":"「サイバーセキュリティ基本法」の設問では、「基本理念」「国の責務」「地方公共団体」「重要社会基盤」「事業者」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、不正アクセス禁止法や個人情報保護法の説明と混ぜないことが判断線です。","examFocusZh":"看到「ー基本法」相关题时，先抓基本理念、国家责任、地方公共团体、重要基础设施、事业者是判断词。再判断题目问对象、责任、流程还是效果，并排除非法访问禁止法或个人信息保护法。","commonMistakeJa":"「サイバーセキュリティ基本法」を不正アクセス禁止法や個人情報保護法と混同すると誤答します。特に基本法を個人のアクセス禁止行為を細かく定める法律と考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「ー基本法」和非法访问禁止法或个人信息保护法混淆，尤其是误以为基本法详细规定个人非法访问行为。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":264,"pdfPageEnd":265,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-1 サイバーセキュリティ基本法","anchorTermsJa":["サイバーセキュリティ基本法"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、サイバーセキュリティ基本法が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「基本理念」「国の責務」「地方公共団体」「重要社会基盤」「事業者」が判断線です。その語が出たら、まず理解国家、地方公共团体、重要基础设施和企业在网络安全中的基本责任という意味に対応する日本語条件を探します。合わない場合は、不正アクセス禁止法や個人情報保護法を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“日本网络安全基本法基本框架”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Cybersecurity Basic Act","Critical Infrastructure","Responsibility"],"examFocusJa":"サイバーセキュリティ基本法の見分け方は、「基本理念」「国の責務」「地方公共団体」「重要社会基盤」「事業者」が判断線ですを文章中から拾い、不正アクセス禁止法や個人情報保護法ではなくサイバーセキュリティ基本法を答えるべき条件かを確認することです。","examFocusZh":"网络安全基本法的判断线索是基本理念、国家责任、地方公共团体、重要基础设施、事业者是判断词，同时确认题干要求的是否是「ー基本法」，而不是非法访问禁止法或个人信息保护法。","commonMistakeJa":"サイバーセキュリティ基本法ではなく不正アクセス禁止法や個人情報保護法の説明を選ぶ誤りに注意します。原因は、基本法を個人のアクセス禁止行為を細かく定める法律と考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「ー基本法」（网络安全基本法）和非法访问禁止法或个人信息保护法混淆。错误通常来自误以为基本法详细规定个人非法访问行为，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":264,"pdfPageEnd":265,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-1 サイバーセキュリティ基本法","anchorTermsJa":["サイバーセキュリティ基本法"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Cybersecurity Basic Act","termZh":"Cybersecurity Basic Act","english":"Cybersecurity Basic Act","definitionZh":"Cybersecurity Basic Act是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Cybersecurity Basic Actに関する基本概念。","examCueZh":"题干出现Cybersecurity Basic Act及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Critical Infrastructure","termZh":"Critical Infrastructure","english":"Critical Infrastructure","definitionZh":"Critical Infrastructure是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Critical Infrastructureに関する基本概念。","examCueZh":"题干出现Critical Infrastructure及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Responsibility","termZh":"Responsibility","english":"Responsibility","definitionZh":"Responsibility是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Responsibilityに関する基本概念。","examCueZh":"题干出现Responsibility及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"サイバーセキュリティ基本法と不正アクセス禁止法や個人情報保護法を混同する","trapZh":"把网络安全基本法和非法访问禁止法或个人信息保护法混为一谈。"},{"trapJa":"基本法を個人のアクセス禁止行為を細かく定める法律と考える","trapZh":"误以为基本法详细规定个人非法访问行为"}],"relatedQuestionIds":["q-sg-lesson-0033"],"practiceStatus":"has_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":264,"pdfPageEnd":265,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-1 サイバーセキュリティ基本法","anchorTermsJa":["サイバーセキュリティ基本法"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握日本网络安全基本法基本框架的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。","goalJa":"問題文の条件を読み取り、「サイバーセキュリティ基本法」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"日本网络安全基本法基本框架：从业务问题出发的课堂讲解","headingJa":"5-1-1 サイバーセキュリティ基本法","bodyZh":"日本网络安全基本法基本框架不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Cybersecurity Basic Act、Critical Infrastructure、Responsibility，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待日本网络安全基本法基本框架","bodyZh":"对企业而言，日本网络安全基本法基本框架直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“日本网络安全基本法基本框架”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Cybersecurity Basic Act、Critical Infrastructure、Responsibility是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐日本网络安全基本法基本框架对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查日本网络安全基本法基本框架：问最恰当说明、最优先控制或易混淆概念。关键词多与Cybersecurity Basic Act、Critical Infrastructure、Responsibility相关。","keywords":["Cybersecurity Basic Act","Critical Infrastructure","Responsibility"]},"examCues":[{"cueZh":"题干出现Cybersecurity Basic Act及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。日本网络安全基本法基本框架的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"日本网络安全基本法基本框架三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推日本网络安全基本法基本框架控制。"}],"quizMapping":{"relatedQuestionIds":["q-sg-lesson-0033"],"explanationZh":"本单元已关联既有课程题 1 道，用于检验你是否能把“日本网络安全基本法基本框架”映射到条件判断与对策选择，而不是只识别名词。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-1-2","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":2,"nativeSectionId":"5-1-2","titleJa":"5-1-2 不正アクセス禁止法","titleZh":"禁止非法访问法","overviewJa":"不正アクセス禁止法は、SG法務分野で不正アクセス禁止法では、他人のIDやパスワードを無断利用してアクセス制御を突破する行為、識別符号の不正取得や提供などが問題になります。攻撃結果より、アクセス権限の有無と識別符号の扱いを見ます。PDF 266-267ページの「不正アクセス禁止法」を定位語に、試験では「識別符号」「アクセス制御」「なりすまし」「不正取得」「不正提供」が判断線です。サイバーセキュリティ基本法や刑法との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"非法访问禁止法用于禁止无权限访问、冒用识别符号和助长非法访问的行为。本单元依据 PDF 266-267 页的「不正禁止法」定位，重点理解：非法访问禁止法关注冒用他人 ID/密码、突破访问控制、不正取得或提供识别符号。判断时看有没有权限，以及识别符号如何被使用。考试常用识别符号、访问控制、冒充、不正取得、不正提供是判断词来换说法；同时要和网络安全基本法或刑法区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「不正アクセス禁止法」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“禁止非法访问法”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"不正アクセス禁止法を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。不正アクセス禁止法では、他人のIDやパスワードを無断利用してアクセス制御を突破する行為、識別符号の不正取得や提供などが問題になります。攻撃結果より、アクセス権限の有無と識別符号の扱いを見ます。この関係を押さえると、不正アクセス禁止法は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではUnauthorized Access、ID、Password、Access Controlが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“禁止非法访问法”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Unauthorized Access","ID","Password","Access Control"],"examFocusJa":"「不正アクセス禁止法」の設問では、「識別符号」「アクセス制御」「なりすまし」「不正取得」「不正提供」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、サイバーセキュリティ基本法や刑法の説明と混ぜないことが判断線です。","examFocusZh":"看到「不正禁止法」相关题时，先抓识别符号、访问控制、冒充、不正取得、不正提供是判断词。再判断题目问对象、责任、流程还是效果，并排除网络安全基本法或刑法。","commonMistakeJa":"「不正アクセス禁止法」をサイバーセキュリティ基本法や刑法と混同すると誤答します。特に被害が出なければ不正アクセスではないと考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「不正禁止法」和网络安全基本法或刑法混淆，尤其是误以为没有造成损害就不构成非法访问。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":266,"pdfPageEnd":267,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-2 不正アクセス禁止法","anchorTermsJa":["不正アクセス禁止法"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、不正アクセス禁止法が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「識別符号」「アクセス制御」「なりすまし」「不正取得」「不正提供」が判断線です。その語が出たら、まず禁止无权限访问、冒用识别符号和助长非法访问的行为という意味に対応する日本語条件を探します。合わない場合は、サイバーセキュリティ基本法や刑法を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“禁止非法访问法”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Unauthorized Access","ID","Password","Access Control"],"examFocusJa":"不正アクセス禁止法の見分け方は、「識別符号」「アクセス制御」「なりすまし」「不正取得」「不正提供」が判断線ですを文章中から拾い、サイバーセキュリティ基本法や刑法ではなく不正アクセス禁止法を答えるべき条件かを確認することです。","examFocusZh":"非法访问禁止法的判断线索是识别符号、访问控制、冒充、不正取得、不正提供是判断词，同时确认题干要求的是否是「不正禁止法」，而不是网络安全基本法或刑法。","commonMistakeJa":"不正アクセス禁止法ではなくサイバーセキュリティ基本法や刑法の説明を選ぶ誤りに注意します。原因は、被害が出なければ不正アクセスではないと考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「不正禁止法」（非法访问禁止法）和网络安全基本法或刑法混淆。错误通常来自误以为没有造成损害就不构成非法访问，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":266,"pdfPageEnd":267,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-2 不正アクセス禁止法","anchorTermsJa":["不正アクセス禁止法"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Unauthorized Access","termZh":"Unauthorized Access","english":"Unauthorized Access","definitionZh":"Unauthorized Access是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Unauthorized Accessに関する基本概念。","examCueZh":"题干出现Unauthorized Access及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"ID","termZh":"ID","english":"ID","definitionZh":"ID是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"IDに関する基本概念。","examCueZh":"题干出现ID及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Password","termZh":"Password","english":"Password","definitionZh":"Password是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Passwordに関する基本概念。","examCueZh":"题干出现Password及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Access Control","termZh":"Access Control","english":"Access Control","definitionZh":"Access Control是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Access Controlに関する基本概念。","examCueZh":"题干出现Access Control及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"不正アクセス禁止法とサイバーセキュリティ基本法や刑法を混同する","trapZh":"把非法访问禁止法和网络安全基本法或刑法混为一谈。"},{"trapJa":"被害が出なければ不正アクセスではないと考える","trapZh":"误以为没有造成损害就不构成非法访问"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":266,"pdfPageEnd":267,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-2 不正アクセス禁止法","anchorTermsJa":["不正アクセス禁止法"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握禁止非法访问法的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。目标要可检查。","goalJa":"問題文の条件を読み取り、「不正アクセス禁止法」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"禁止非法访问法：从业务问题出发的课堂讲解","headingJa":"5-1-2 不正アクセス禁止法","bodyZh":"禁止非法访问法不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Unauthorized Access、ID、Password、Access Control，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待禁止非法访问法","bodyZh":"对企业而言，禁止非法访问法直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“禁止非法访问法”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Unauthorized Access、ID、Password、Access Control是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐禁止非法访问法对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查禁止非法访问法：问最恰当说明、最优先控制或易混淆概念。关键词多与Unauthorized Access、ID、Password、Access Control相关。","keywords":["Unauthorized Access","ID","Password","Access Control"]},"examCues":[{"cueZh":"题干出现Unauthorized Access及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。禁止非法访问法的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"禁止非法访问法三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推禁止非法访问法控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“禁止非法访问法”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-1-3","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":3,"nativeSectionId":"5-1-3","titleJa":"5-1-3 個人情報保護法","titleZh":"个人信息保护法","overviewJa":"個人情報保護法は、SG法務分野で個人情報保護法では、利用目的の特定、適正取得、安全管理措置、第三者提供、本人からの開示や訂正請求などを扱います。個人を識別できる情報か、事業者がどの目的で扱うかを確認します。PDF 268-272ページの「個人情報保護法」を定位語に、試験では「個人情報」「利用目的」「第三者提供」「安全管理措置」「開示請求」「本人同意」が判断線です。不正アクセス禁止法や知的財産権との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"个人信息保护法用于规范个人信息取得、利用、保存、第三方提供和本人权利处理。本单元依据 PDF 268-272 页的「個人情報保護法」定位，重点理解：个人信息保护法规范使用目的、适当取得、安全管理、第三方提供、本人开示和更正请求。要看该信息是否能识别个人，以及事业者以什么目的处理。考试常用个人信息、使用目的、第三方提供、安全管理措施、开示请求、本人同意是判断词来换说法；同时要和非法访问禁止法或知识产权区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「個人情報保護法」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“个人信息保护法”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"個人情報保護法を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。個人情報保護法では、利用目的の特定、適正取得、安全管理措置、第三者提供、本人からの開示や訂正請求などを扱います。個人を識別できる情報か、事業者がどの目的で扱うかを確認します。この関係を押さえると、個人情報保護法は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではPersonal Information、Consent、Third-party Provision、Disclosure Requestが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“个人信息保护法”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Personal Information","Consent","Third-party Provision","Disclosure Request"],"examFocusJa":"「個人情報保護法」の設問では、「個人情報」「利用目的」「第三者提供」「安全管理措置」「開示請求」「本人同意」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、不正アクセス禁止法や知的財産権の説明と混ぜないことが判断線です。","examFocusZh":"看到「個人情報保護法」相关题时，先抓个人信息、使用目的、第三方提供、安全管理措施、开示请求、本人同意是判断词。再判断题目问对象、责任、流程还是效果，并排除非法访问禁止法或知识产权。","commonMistakeJa":"「個人情報保護法」を不正アクセス禁止法や知的財産権と混同すると誤答します。特に社内利用なら目的外利用も自由と考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「個人情報保護法」和非法访问禁止法或知识产权混淆，尤其是误以为公司内部使用就可以随意超出目的使用。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":268,"pdfPageEnd":272,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-3 個人情報保護法","anchorTermsJa":["個人情報保護法"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、個人情報保護法が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「個人情報」「利用目的」「第三者提供」「安全管理措置」「開示請求」「本人同意」が判断線です。その語が出たら、まず规范个人信息取得、利用、保存、第三方提供和本人权利处理という意味に対応する日本語条件を探します。合わない場合は、不正アクセス禁止法や知的財産権を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“个人信息保护法”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Personal Information","Consent","Third-party Provision","Disclosure Request"],"examFocusJa":"個人情報保護法の見分け方は、「個人情報」「利用目的」「第三者提供」「安全管理措置」「開示請求」「本人同意」が判断線ですを文章中から拾い、不正アクセス禁止法や知的財産権ではなく個人情報保護法を答えるべき条件かを確認することです。","examFocusZh":"个人信息保护法的判断线索是个人信息、使用目的、第三方提供、安全管理措施、开示请求、本人同意是判断词，同时确认题干要求的是否是「個人情報保護法」，而不是非法访问禁止法或知识产权。","commonMistakeJa":"個人情報保護法ではなく不正アクセス禁止法や知的財産権の説明を選ぶ誤りに注意します。原因は、社内利用なら目的外利用も自由と考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「個人情報保護法」（个人信息保护法）和非法访问禁止法或知识产权混淆。错误通常来自误以为公司内部使用就可以随意超出目的使用，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":268,"pdfPageEnd":272,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-3 個人情報保護法","anchorTermsJa":["個人情報保護法"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Personal Information","termZh":"Personal Information","english":"Personal Information","definitionZh":"Personal Information是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Personal Informationに関する基本概念。","examCueZh":"题干出现Personal Information及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Consent","termZh":"Consent","english":"Consent","definitionZh":"Consent是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Consentに関する基本概念。","examCueZh":"题干出现Consent及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Third-party Provision","termZh":"Third-party Provision","english":"Third-party Provision","definitionZh":"Third-party Provision是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Third-party Provisionに関する基本概念。","examCueZh":"题干出现Third-party Provision及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Disclosure Request","termZh":"Disclosure Request","english":"Disclosure Request","definitionZh":"Disclosure Request是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Disclosure Requestに関する基本概念。","examCueZh":"题干出现Disclosure Request及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"個人情報保護法と不正アクセス禁止法や知的財産権を混同する","trapZh":"把个人信息保护法和非法访问禁止法或知识产权混为一谈。"},{"trapJa":"社内利用なら目的外利用も自由と考える","trapZh":"误以为公司内部使用就可以随意超出目的使用"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":268,"pdfPageEnd":272,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-3 個人情報保護法","anchorTermsJa":["個人情報保護法"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握个人信息保护法的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。目标要可检查。","goalJa":"問題文の条件を読み取り、「個人情報保護法」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"个人信息保护法：从业务问题出发的课堂讲解","headingJa":"5-1-3 個人情報保護法","bodyZh":"个人信息保护法不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Personal Information、Consent、Third-party Provision、Disclosure Request，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待个人信息保护法","bodyZh":"对企业而言，个人信息保护法直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“个人信息保护法”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Personal Information、Consent、Third-party Provision、Disclosure Request是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐个人信息保护法对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查个人信息保护法：问最恰当说明、最优先控制或易混淆概念。关键词多与Personal Information、Consent、Third-party Provision、Disclosure Request相关。","keywords":["Personal Information","Consent","Third-party Provision","Disclosure Request"]},"examCues":[{"cueZh":"题干出现Personal Information及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。个人信息保护法的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"个人信息保护法三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推个人信息保护法控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“个人信息保护法”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-1-4","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":4,"nativeSectionId":"5-1-4","titleJa":"5-1-4 刑法","titleZh":"刑法","overviewJa":"刑法は、SG法務分野で刑法では、電子計算機損壊等業務妨害、電磁的記録不正作出、詐欺などが情報システムに関係します。アクセス制御だけでなく、業務妨害や記録の不正作出という行為の性質を読みます。PDF 273-274ページの「刑法」を定位語に、試験では「電子計算機損壊」「業務妨害」「電磁的記録」「不正作出」「詐欺」が判断線です。不正アクセス禁止法や個人情報保護法との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"刑法用于理解计算机相关犯罪中数据破坏、业务妨害、电子记录不正作出等违法性。本单元依据 PDF 273-274 页的「刑法」定位，重点理解：刑法中的计算机相关犯罪包括破坏计算机业务、伪造电磁记录、诈骗等。判断时不只看访问控制，还要看是否妨害业务或制作不正记录。考试常用计算机损坏、业务妨害、电磁记录、不正作出、诈骗是判断词来换说法；同时要和非法访问禁止法或个人信息保护法区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「刑法」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“刑法”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"刑法を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。刑法では、電子計算機損壊等業務妨害、電磁的記録不正作出、詐欺などが情報システムに関係します。アクセス制御だけでなく、業務妨害や記録の不正作出という行為の性質を読みます。この関係を押さえると、刑法は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではCriminal Law、Computer Crime、Fraud、Electromagnetic Recordが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“刑法”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。若讲解停留在定义层，遇到案例题仍会失分。","englishTerms":["Criminal Law","Computer Crime","Fraud","Electromagnetic Record"],"examFocusJa":"「刑法」の設問では、「電子計算機損壊」「業務妨害」「電磁的記録」「不正作出」「詐欺」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、不正アクセス禁止法や個人情報保護法の説明と混ぜないことが判断線です。","examFocusZh":"看到「刑法」相关题时，先抓计算机损坏、业务妨害、电磁记录、不正作出、诈骗是判断词。再判断题目问对象、责任、流程还是效果，并排除非法访问禁止法或个人信息保护法。","commonMistakeJa":"「刑法」を不正アクセス禁止法や個人情報保護法と混同すると誤答します。特にコンピュータ犯罪はすべて不正アクセス禁止法だけで扱うと考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「刑法」和非法访问禁止法或个人信息保护法混淆，尤其是误以为所有计算机犯罪都只由非法访问禁止法处理。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":273,"pdfPageEnd":274,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-4 刑法","anchorTermsJa":["刑法"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、刑法が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「電子計算機損壊」「業務妨害」「電磁的記録」「不正作出」「詐欺」が判断線です。その語が出たら、まず理解计算机相关犯罪中数据破坏、业务妨害、电子记录不正作出等违法性という意味に対応する日本語条件を探します。合わない場合は、不正アクセス禁止法や個人情報保護法を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“刑法”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。若讲解停留在定义层，遇到案例题仍会失分。","englishTerms":["Criminal Law","Computer Crime","Fraud","Electromagnetic Record"],"examFocusJa":"刑法の見分け方は、「電子計算機損壊」「業務妨害」「電磁的記録」「不正作出」「詐欺」が判断線ですを文章中から拾い、不正アクセス禁止法や個人情報保護法ではなく刑法を答えるべき条件かを確認することです。","examFocusZh":"刑法的判断线索是计算机损坏、业务妨害、电磁记录、不正作出、诈骗是判断词，同时确认题干要求的是否是「刑法」，而不是非法访问禁止法或个人信息保护法。","commonMistakeJa":"刑法ではなく不正アクセス禁止法や個人情報保護法の説明を選ぶ誤りに注意します。原因は、コンピュータ犯罪はすべて不正アクセス禁止法だけで扱うと考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「刑法」（刑法）和非法访问禁止法或个人信息保护法混淆。错误通常来自误以为所有计算机犯罪都只由非法访问禁止法处理，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":273,"pdfPageEnd":274,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-4 刑法","anchorTermsJa":["刑法"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Criminal Law","termZh":"Criminal Law","english":"Criminal Law","definitionZh":"Criminal Law是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Criminal Lawに関する基本概念。","examCueZh":"题干出现Criminal Law及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Computer Crime","termZh":"Computer Crime","english":"Computer Crime","definitionZh":"Computer Crime是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Computer Crimeに関する基本概念。","examCueZh":"题干出现Computer Crime及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Fraud","termZh":"Fraud","english":"Fraud","definitionZh":"Fraud是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Fraudに関する基本概念。","examCueZh":"题干出现Fraud及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Electromagnetic Record","termZh":"Electromagnetic Record","english":"Electromagnetic Record","definitionZh":"Electromagnetic Record是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Electromagnetic Recordに関する基本概念。","examCueZh":"题干出现Electromagnetic Record及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"刑法と不正アクセス禁止法や個人情報保護法を混同する","trapZh":"把刑法和非法访问禁止法或个人信息保护法混为一谈。"},{"trapJa":"コンピュータ犯罪はすべて不正アクセス禁止法だけで扱うと考える","trapZh":"误以为所有计算机犯罪都只由非法访问禁止法处理"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":273,"pdfPageEnd":274,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-4 刑法","anchorTermsJa":["刑法"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握刑法的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。目标要可检查。","goalJa":"問題文の条件を読み取り、「刑法」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"刑法：从业务问题出发的课堂讲解","headingJa":"5-1-4 刑法","bodyZh":"刑法不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Criminal Law、Computer Crime、Fraud、Electromagnetic Record，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待刑法","bodyZh":"对企业而言，刑法直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“刑法”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Criminal Law、Computer Crime、Fraud、Electromagnetic Record是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐刑法对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查刑法：问最恰当说明、最优先控制或易混淆概念。关键词多与Criminal Law、Computer Crime、Fraud、Electromagnetic Record相关。","keywords":["Criminal Law","Computer Crime","Fraud","Electromagnetic Record"]},"examCues":[{"cueZh":"题干出现Criminal Law及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。刑法的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"刑法三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推刑法控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“刑法”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-1-5","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":5,"nativeSectionId":"5-1-5","titleJa":"5-1-5 その他のセキュリティ関連法規・基準","titleZh":"そ的他的安全関連法规、基準","overviewJa":"その他のセキュリティ関連法規・基準は、SG法務分野でその他の法規や基準では、ガイドライン、業界基準、政府統一基準、個別制度を扱います。法律としての義務なのか、基準や指針として遵守すべきものなのかを分けて読みます。PDF 275-278ページの「その他のセキュリティ関連法規」を定位語に、試験では「ガイドライン」「基準」「政府統一基準」「法規」「遵守」「制度」が判断線です。個別法律名や標準化関連との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"其他安全相关法规与标准用于把安全相关指南、标准、制度和行业要求放在合规框架中理解。本单元依据 PDF 275-278 页的「他関連法規」定位，重点理解：其他安全法规和标准包括指南、行业标准、政府统一基准和个别制度。要区分法律义务、行业要求和推荐性指南。考试常用指南、基准、政府统一基准、法规、遵守、制度是判断词来换说法；同时要和具体法律名或标准化相关内容区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「その他のセキュリティ関連法規・基準」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“的他的安全関連法规、基準”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"その他のセキュリティ関連法規・基準を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。その他の法規や基準では、ガイドライン、業界基準、政府統一基準、個別制度を扱います。法律としての義務なのか、基準や指針として遵守すべきものなのかを分けて読みます。この関係を押さえると、その他のセキュリティ関連法規・基準は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではGuideline、Standard、Compliance、Government Standardが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“的他的安全関連法规、基準”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Guideline","Standard","Compliance","Government Standard"],"examFocusJa":"「その他のセキュリティ関連法規・基準」の設問では、「ガイドライン」「基準」「政府統一基準」「法規」「遵守」「制度」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、個別法律名や標準化関連の説明と混ぜないことが判断線です。","examFocusZh":"看到「他関連法規・基準」相关题时，先抓指南、基准、政府统一基准、法规、遵守、制度是判断词。再判断题目问对象、责任、流程还是效果，并排除具体法律名或标准化相关内容。","commonMistakeJa":"「その他のセキュリティ関連法規・基準」を個別法律名や標準化関連と混同すると誤答します。特にガイドラインをすべて罰則付き法律と考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「他関連法規・基準」和具体法律名或标准化相关内容混淆，尤其是把所有指南都误当成带处罚的法律。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":275,"pdfPageEnd":278,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-5 その他のセキュリティ関連法規・基準","anchorTermsJa":["その他のセキュリティ関連法規","基準"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、その他のセキュリティ関連法規・基準が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「ガイドライン」「基準」「政府統一基準」「法規」「遵守」「制度」が判断線です。その語が出たら、まず把安全相关指南、标准、制度和行业要求放在合规框架中理解という意味に対応する日本語条件を探します。合わない場合は、個別法律名や標準化関連を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“的他的安全関連法规、基準”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Guideline","Standard","Compliance","Government Standard"],"examFocusJa":"その他のセキュリティ関連法規・基準の見分け方は、「ガイドライン」「基準」「政府統一基準」「法規」「遵守」「制度」が判断線ですを文章中から拾い、個別法律名や標準化関連ではなくその他のセキュリティ関連法規・基準を答えるべき条件かを確認することです。","examFocusZh":"其他安全相关法规与标准的判断线索是指南、基准、政府统一基准、法规、遵守、制度是判断词，同时确认题干要求的是否是「他関連法規・基準」，而不是具体法律名或标准化相关内容。","commonMistakeJa":"その他のセキュリティ関連法規・基準ではなく個別法律名や標準化関連の説明を選ぶ誤りに注意します。原因は、ガイドラインをすべて罰則付き法律と考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「他関連法規・基準」（其他安全相关法规与标准）和具体法律名或标准化相关内容混淆。错误通常来自把所有指南都误当成带处罚的法律，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":275,"pdfPageEnd":278,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-5 その他のセキュリティ関連法規・基準","anchorTermsJa":["その他のセキュリティ関連法規","基準"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Guideline","termZh":"Guideline","english":"Guideline","definitionZh":"Guideline是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Guidelineに関する基本概念。","examCueZh":"题干出现Guideline及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Standard","termZh":"Standard","english":"Standard","definitionZh":"Standard是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Standardに関する基本概念。","examCueZh":"题干出现Standard及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Compliance","termZh":"Compliance","english":"Compliance","definitionZh":"Compliance是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Complianceに関する基本概念。","examCueZh":"题干出现Compliance及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Government Standard","termZh":"Government Standard","english":"Government Standard","definitionZh":"Government Standard是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Government Standardに関する基本概念。","examCueZh":"题干出现Government Standard及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"その他のセキュリティ関連法規・基準と個別法律名や標準化関連を混同する","trapZh":"把其他安全相关法规与标准和具体法律名或标准化相关内容混为一谈。"},{"trapJa":"ガイドラインをすべて罰則付き法律と考える","trapZh":"把所有指南都误当成带处罚的法律。要写清错在哪里。"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":275,"pdfPageEnd":278,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-5 その他のセキュリティ関連法規・基準","anchorTermsJa":["その他のセキュリティ関連法規","基準"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握的他的安全関連法规、基準的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。","goalJa":"問題文の条件を読み取り、「その他のセキュリティ関連法規・基準」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"的他的安全関連法规、基準：从业务问题出发的课堂讲解","headingJa":"5-1-5 その他のセキュリティ関連法規・基準","bodyZh":"的他的安全関連法规、基準不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Guideline、Standard、Compliance、Government Standard，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待的他的安全関連法规、基準","bodyZh":"对企业而言，的他的安全関連法规、基準直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“的他的安全関連法规、基準”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Guideline、Standard、Compliance、Government Standard是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐的他的安全関連法规、基準对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查的他的安全関連法规、基準：问最恰当说明、最优先控制或易混淆概念。关键词多与Guideline、Standard、Compliance、Government Standard相关。","keywords":["Guideline","Standard","Compliance","Government Standard"]},"examCues":[{"cueZh":"题干出现Guideline及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。的他的安全関連法规、基準的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"的他的安全関連法规、基準三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推的他的安全関連法规、基準控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“的他的安全関連法规、基準”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-1-6","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":6,"nativeSectionId":"5-1-6","titleJa":"5-1-6 演習問題","titleZh":"练习题","overviewJa":"演習問題は、SG演習分野で演習問題では、どの法律や基準が、どの行為や義務に対応するかを問います。アクセス権限、個人識別性、業務妨害、組織責務を分けて読むことが重要です。PDF 279-286ページの「演習問題」を定位語に、試験では「演習問題」「法規」「不正アクセス」「個人情報」「刑法」「基準」が判断線です。攻撃手法や技術対策問題との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"安全法规演习问题用于检查网络安全基本法、非法访问、个人信息、刑法和其他基准的适用区别。本单元依据 PDF 279-286 页的「演習問題」定位，重点理解：本节演习把网络安全基本法、非法访问、个人信息、刑法和其他基准混合考。要分清访问权限、个人识别性、业务妨害和组织责任。考试常用演习问题、法规、非法访问、个人信息、刑法、基准是判断词来换说法；同时要和攻击手法或技术对策题区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「演習問題」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“练习题”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"演習問題を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。演習問題では、どの法律や基準が、どの行為や義務に対応するかを問います。アクセス権限、個人識別性、業務妨害、組織責務を分けて読むことが重要です。この関係を押さえると、演習問題は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではExercise、Law、Compliance、Personal Informationが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“练习题”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。若讲解停留在定义层，遇到案例题仍会失分。","englishTerms":["Exercise","Law","Compliance","Personal Information"],"examFocusJa":"「演習問題」の設問では、「演習問題」「法規」「不正アクセス」「個人情報」「刑法」「基準」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、攻撃手法や技術対策問題の説明と混ぜないことが判断線です。","examFocusZh":"看到「演習問題」相关题时，先抓演习问题、法规、非法访问、个人信息、刑法、基准是判断词。再判断题目问对象、责任、流程还是效果，并排除攻击手法或技术对策题。","commonMistakeJa":"「演習問題」を攻撃手法や技術対策問題と混同すると誤答します。特に法律名だけで選び、行為要件を読まない場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「演習問題」和攻击手法或技术对策题混淆，尤其是只看法律名，不读行为要件。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":279,"pdfPageEnd":286,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-6 演習問題","anchorTermsJa":["演習問題"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、演習問題が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「演習問題」「法規」「不正アクセス」「個人情報」「刑法」「基準」が判断線です。その語が出たら、まず检查网络安全基本法、非法访问、个人信息、刑法和其他基准的适用区别という意味に対応する日本語条件を探します。合わない場合は、攻撃手法や技術対策問題を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“练习题”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Exercise","Law","Compliance","Personal Information"],"examFocusJa":"演習問題の見分け方は、「演習問題」「法規」「不正アクセス」「個人情報」「刑法」「基準」が判断線ですを文章中から拾い、攻撃手法や技術対策問題ではなく演習問題を答えるべき条件かを確認することです。","examFocusZh":"安全法规演习问题的判断线索是演习问题、法规、非法访问、个人信息、刑法、基准是判断词，同时确认题干要求的是否是「演習問題」，而不是攻击手法或技术对策题。","commonMistakeJa":"演習問題ではなく攻撃手法や技術対策問題の説明を選ぶ誤りに注意します。原因は、法律名だけで選び、行為要件を読まないときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「演習問題」（安全法规演习问题）和攻击手法或技术对策题混淆。错误通常来自只看法律名，不读行为要件，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":279,"pdfPageEnd":286,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-6 演習問題","anchorTermsJa":["演習問題"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Exercise","termZh":"Exercise","english":"Exercise","definitionZh":"Exercise是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Exerciseに関する基本概念。","examCueZh":"题干出现Exercise及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Law","termZh":"Law","english":"Law","definitionZh":"Law是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Lawに関する基本概念。","examCueZh":"题干出现Law及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Compliance","termZh":"Compliance","english":"Compliance","definitionZh":"Compliance是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Complianceに関する基本概念。","examCueZh":"题干出现Compliance及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Personal Information","termZh":"Personal Information","english":"Personal Information","definitionZh":"Personal Information是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Personal Informationに関する基本概念。","examCueZh":"题干出现Personal Information及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"演習問題と攻撃手法や技術対策問題を混同する","trapZh":"把安全法规演习问题和攻击手法或技术对策题混为一谈。"},{"trapJa":"法律名だけで選び、行為要件を読まない","trapZh":"只看法律名，不读行为要件。要写清错在哪里。"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":279,"pdfPageEnd":286,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-1-6 演習問題","anchorTermsJa":["演習問題"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握练习题的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。目标要可检查。","goalJa":"問題文の条件を読み取り、「演習問題」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"练习题：从业务问题出发的课堂讲解","headingJa":"5-1-6 演習問題","bodyZh":"练习题不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Exercise、Law、Compliance、Personal Information，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待练习题","bodyZh":"对企业而言，练习题直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“练习题”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Exercise、Law、Compliance、Personal Information是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐练习题对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"综合题会把练习题放进长案例，要求先读条件再选对策。干扰项常给出“正确术语但不符合当前情境”的选项。做题时先标注对象、影响、约束条件，再回看选项。","keywords":["Exercise","Law","Compliance","Personal Information"]},"examCues":[{"cueZh":"题干出现Exercise及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。练习题的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"练习题三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推练习题控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“练习题”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-2-1","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":7,"nativeSectionId":"5-2-1","titleJa":"5-2-1 知的財産権","titleZh":"5-2-1 知识产权分类保护 (专利权/著作权/商标权)","overviewJa":"知的財産権は、SG法務分野で知的財産権では、著作権、特許権、商標権、営業秘密などを保護対象と成立条件で分けます。ソフトウェア、データベース、ロゴ、技術的発明など、何を守る制度かを読みます。PDF 287-289ページの「知的財産権」を定位語に、試験では「著作権」「特許権」「商標権」「営業秘密」「ライセンス」「侵害」が判断線です。個人情報保護法や標準化関連との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"知识产权用于保护著作物、发明、商标和商业秘密，并判断授权和侵权。本单元依据 PDF 287-289 页的「知的財産権」定位，重点理解：知识产权要按保护对象和成立条件区分著作权、专利权、商标权、商业秘密。软件、数据库、Logo、技术发明分别适用的权利不同。考试常用著作权、专利权、商标权、商业秘密、许可、侵权是判断词来换说法；同时要和个人信息保护法或标准化区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「知的財産権」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“5-2-1 知识产权分类保护 (专利权/著作权/商标权)”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"知的財産権を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。知的財産権では、著作権、特許権、商標権、営業秘密などを保護対象と成立条件で分けます。ソフトウェア、データベース、ロゴ、技術的発明など、何を守る制度かを読みます。この関係を押さえると、知的財産権は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではCopyright、Patent、Trademark、Trade Secret、Licenseが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“知识产权分类保护 (专利权/著作权/商标权)”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Copyright","Patent","Trademark","Trade Secret","License"],"examFocusJa":"「知的財産権」の設問では、「著作権」「特許権」「商標権」「営業秘密」「ライセンス」「侵害」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、個人情報保護法や標準化関連の説明と混ぜないことが判断線です。","examFocusZh":"看到「知的財産権」相关题时，先抓著作权、专利权、商标权、商业秘密、许可、侵权是判断词。再判断题目问对象、责任、流程还是效果，并排除个人信息保护法或标准化。","commonMistakeJa":"「知的財産権」を個人情報保護法や標準化関連と混同すると誤答します。特にアイデアそのものが著作権で保護されると考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「知的財産権」和个人信息保护法或标准化混淆，尤其是误以为想法本身受著作权保护。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":287,"pdfPageEnd":289,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-1 知的財産権","anchorTermsJa":["知的財産権"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、知的財産権が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「著作権」「特許権」「商標権」「営業秘密」「ライセンス」「侵害」が判断線です。その語が出たら、まず保护著作物、发明、商标和商业秘密，并判断授权和侵权という意味に対応する日本語条件を探します。合わない場合は、個人情報保護法や標準化関連を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“知识产权分类保护 (专利权/著作权/商标权)”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Copyright","Patent","Trademark","Trade Secret","License"],"examFocusJa":"知的財産権の見分け方は、「著作権」「特許権」「商標権」「営業秘密」「ライセンス」「侵害」が判断線ですを文章中から拾い、個人情報保護法や標準化関連ではなく知的財産権を答えるべき条件かを確認することです。","examFocusZh":"知识产权的判断线索是著作权、专利权、商标权、商业秘密、许可、侵权是判断词，同时确认题干要求的是否是「知的財産権」，而不是个人信息保护法或标准化。","commonMistakeJa":"知的財産権ではなく個人情報保護法や標準化関連の説明を選ぶ誤りに注意します。原因は、アイデアそのものが著作権で保護されると考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「知的財産権」（知识产权）和个人信息保护法或标准化混淆。错误通常来自误以为想法本身受著作权保护，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":287,"pdfPageEnd":289,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-1 知的財産権","anchorTermsJa":["知的財産権"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Copyright","termZh":"Copyright","english":"Copyright","definitionZh":"Copyright是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Copyrightに関する基本概念。","examCueZh":"题干出现Copyright及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Patent","termZh":"Patent","english":"Patent","definitionZh":"Patent是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Patentに関する基本概念。","examCueZh":"题干出现Patent及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Trademark","termZh":"Trademark","english":"Trademark","definitionZh":"Trademark是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Trademarkに関する基本概念。","examCueZh":"题干出现Trademark及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Trade Secret","termZh":"Trade Secret","english":"Trade Secret","definitionZh":"Trade Secret是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Trade Secretに関する基本概念。","examCueZh":"题干出现Trade Secret及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"License","termZh":"License","english":"License","definitionZh":"License是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Licenseに関する基本概念。","examCueZh":"题干出现License及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"知的財産権と個人情報保護法や標準化関連を混同する","trapZh":"把知识产权和个人信息保护法或标准化混为一谈。"},{"trapJa":"アイデアそのものが著作権で保護されると考える","trapZh":"误以为想法本身受著作权保护。要写清错在哪里。"}],"relatedQuestionIds":["q-sg-lesson-0034"],"practiceStatus":"has_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":287,"pdfPageEnd":289,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-1 知的財産権","anchorTermsJa":["知的財産権"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握知识产权分类保护 (专利权/著作权/商标权)的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。","goalJa":"問題文の条件を読み取り、「知的財産権」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"知识产权分类保护 (专利权/著作权/商标权)：从业务问题出发的课堂讲解","headingJa":"5-2-1 知的財産権","bodyZh":"知识产权分类保护 (专利权/著作权/商标权)不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Copyright、Patent、Trademark、Trade Secret，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待知识产权分类保护 (专利权/著作权/商标权)","bodyZh":"对企业而言，知识产权分类保护 (专利权/著作权/商标权)直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“知识产权分类保护 (专利权/著作权/商标权)”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Copyright、Patent、Trademark、Trade Secret是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐知识产权分类保护 (专利权/著作权/商标权)对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查知识产权分类保护 (专利权/著作权/商标权)：问最恰当说明、最优先控制或易混淆概念。关键词多与Copyright、Patent、Trademark、Trade Secret相关。","keywords":["Copyright","Patent","Trademark","Trade Secret","License"]},"examCues":[{"cueZh":"题干出现Copyright及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。知识产权分类保护 (专利权/著作权/商标权)的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"知识产权分类保护 (专利权/著作权/商标权)三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推知识产权分类保护 (专利权/著作权/商标权)控制。"}],"quizMapping":{"relatedQuestionIds":["q-sg-lesson-0034"],"explanationZh":"本单元已关联既有课程题 1 道，用于检验你是否能把“知识产权分类保护 (专利权/著作权/商标权)”映射到条件判断与对策选择，而不是只识别名词。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-2-2","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":8,"nativeSectionId":"5-2-2","titleJa":"5-2-2 労働関連・取引関連法規","titleZh":"労働関連、取引関連法规","overviewJa":"労働関連・取引関連法規は、SG法務分野で労働関連・取引関連法規では、派遣、請負、委任、下請取引、契約責任を扱います。誰が作業者へ指揮命令するか、成果物の完成責任を誰が負うかで契約形態を判断します。PDF 290-293ページの「労働関連」を定位語に、試験では「労働者派遣」「請負」「委任」「下請」「指揮命令」「契約責任」が判断線です。知的財産権やセキュリティ法規との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"劳动与交易相关法规用于区分派遣、承揽、委任、下请等合同形态与指挥命令关系。本单元依据 PDF 290-293 页的「労働関連」定位，重点理解：劳动与交易法规要区分派遣、承揽、委任、分包和合同责任。关键是看谁指挥作业人员，谁对成果物完成负责。考试常用劳务派遣、承揽、委任、分包、指挥命令、合同责任是判断词来换说法；同时要和知识产权或安全法规区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「労働関連・取引関連法規」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“労働関連、取引関連法规”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"労働関連・取引関連法規を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。労働関連・取引関連法規では、派遣、請負、委任、下請取引、契約責任を扱います。誰が作業者へ指揮命令するか、成果物の完成責任を誰が負うかで契約形態を判断します。この関係を押さえると、労働関連・取引関連法規は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではDispatch、Outsourcing、Contract、Subcontract、Commandが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“労働関連、取引関連法规”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Dispatch","Outsourcing","Contract","Subcontract","Command"],"examFocusJa":"「労働関連・取引関連法規」の設問では、「労働者派遣」「請負」「委任」「下請」「指揮命令」「契約責任」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、知的財産権やセキュリティ法規の説明と混ぜないことが判断線です。","examFocusZh":"看到「労働関連・取引関連法規」相关题时，先抓劳务派遣、承揽、委任、分包、指挥命令、合同责任是判断词。再判断题目问对象、责任、流程还是效果，并排除知识产权或安全法规。","commonMistakeJa":"「労働関連・取引関連法規」を知的財産権やセキュリティ法規と混同すると誤答します。特に請負でも発注者が作業者へ直接指示してよいと考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「労働関連・取引関連法規」和知识产权或安全法规混淆，尤其是误以为承揽合同中发包方也能直接指挥作业者。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":290,"pdfPageEnd":293,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-2 労働関連・取引関連法規","anchorTermsJa":["労働関連","取引関連法規"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、労働関連・取引関連法規が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「労働者派遣」「請負」「委任」「下請」「指揮命令」「契約責任」が判断線です。その語が出たら、まず区分派遣、承揽、委任、下请等合同形态与指挥命令关系という意味に対応する日本語条件を探します。合わない場合は、知的財産権やセキュリティ法規を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“労働関連、取引関連法规”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Dispatch","Outsourcing","Contract","Subcontract","Command"],"examFocusJa":"労働関連・取引関連法規の見分け方は、「労働者派遣」「請負」「委任」「下請」「指揮命令」「契約責任」が判断線ですを文章中から拾い、知的財産権やセキュリティ法規ではなく労働関連・取引関連法規を答えるべき条件かを確認することです。","examFocusZh":"劳动与交易相关法规的判断线索是劳务派遣、承揽、委任、分包、指挥命令、合同责任是判断词，同时确认题干要求的是否是「労働関連・取引関連法規」，而不是知识产权或安全法规。","commonMistakeJa":"労働関連・取引関連法規ではなく知的財産権やセキュリティ法規の説明を選ぶ誤りに注意します。原因は、請負でも発注者が作業者へ直接指示してよいと考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「労働関連・取引関連法規」（劳动与交易相关法规）和知识产权或安全法规混淆。错误通常来自误以为承揽合同中发包方也能直接指挥作业者，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":290,"pdfPageEnd":293,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-2 労働関連・取引関連法規","anchorTermsJa":["労働関連","取引関連法規"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Dispatch","termZh":"Dispatch","english":"Dispatch","definitionZh":"Dispatch是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Dispatchに関する基本概念。","examCueZh":"题干出现Dispatch及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Outsourcing","termZh":"Outsourcing","english":"Outsourcing","definitionZh":"Outsourcing是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Outsourcingに関する基本概念。","examCueZh":"题干出现Outsourcing及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Contract","termZh":"Contract","english":"Contract","definitionZh":"Contract是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Contractに関する基本概念。","examCueZh":"题干出现Contract及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Subcontract","termZh":"Subcontract","english":"Subcontract","definitionZh":"Subcontract是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Subcontractに関する基本概念。","examCueZh":"题干出现Subcontract及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Command","termZh":"Command","english":"Command","definitionZh":"Command是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Commandに関する基本概念。","examCueZh":"题干出现Command及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"労働関連・取引関連法規と知的財産権やセキュリティ法規を混同する","trapZh":"把劳动与交易相关法规和知识产权或安全法规混为一谈。"},{"trapJa":"請負でも発注者が作業者へ直接指示してよいと考える","trapZh":"误以为承揽合同中发包方也能直接指挥作业者"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":290,"pdfPageEnd":293,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-2 労働関連・取引関連法規","anchorTermsJa":["労働関連","取引関連法規"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握労働関連、取引関連法规的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。","goalJa":"問題文の条件を読み取り、「労働関連・取引関連法規」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"労働関連、取引関連法规：从业务问题出发的课堂讲解","headingJa":"5-2-2 労働関連・取引関連法規","bodyZh":"労働関連、取引関連法规不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Dispatch、Outsourcing、Contract、Subcontract，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待労働関連、取引関連法规","bodyZh":"对企业而言，労働関連、取引関連法规直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“労働関連、取引関連法规”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Dispatch、Outsourcing、Contract、Subcontract是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐労働関連、取引関連法规对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查労働関連、取引関連法规：问最恰当说明、最优先控制或易混淆概念。关键词多与Dispatch、Outsourcing、Contract、Subcontract相关。","keywords":["Dispatch","Outsourcing","Contract","Subcontract","Command"]},"examCues":[{"cueZh":"题干出现Dispatch及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。労働関連、取引関連法规的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"労働関連、取引関連法规三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推労働関連、取引関連法规控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“労働関連、取引関連法规”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-2-3","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":9,"nativeSectionId":"5-2-3","titleJa":"5-2-3 その他の法律・ガイドライン・技術者倫理","titleZh":"そ的他的法律、ガイドライン、技术者倫理","overviewJa":"その他の法律・ガイドライン・技術者倫理は、SG法務分野で技術者倫理では、法令遵守だけでなく、利用者安全、公正性、説明責任、社会的影響への配慮が問われます。ガイドラインは行動の判断基準になり、法律違反でなくても倫理上問題となる場合があります。PDF 294-296ページの「その他の法律」を定位語に、試験では「技術者倫理」「ガイドライン」「説明責任」「公正性」「社会的影響」「法令遵守」が判断線です。個別法律の罰則問題との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"其他法律、指南与技术者伦理用于理解工程师在法律、指南、伦理和社会责任之间的判断边界。本单元依据 PDF 294-296 页的「他法律」定位，重点理解：技术者伦理不只是不违法，还要考虑用户安全、公正性、说明责任和社会影响。指南提供行为判断基准，即使不违法也可能有伦理问题。考试常用技术者伦理、指南、说明责任、公正性、社会影响、合规是判断词来换说法；同时要和具体法律处罚题区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「その他の法律・ガイドライン・技術者倫理」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“的他的法律、、技术者倫理”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"その他の法律・ガイドライン・技術者倫理を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。技術者倫理では、法令遵守だけでなく、利用者安全、公正性、説明責任、社会的影響への配慮が問われます。ガイドラインは行動の判断基準になり、法律違反でなくても倫理上問題となる場合があります。この関係を押さえると、その他の法律・ガイドライン・技術者倫理は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではEngineer Ethics、Guideline、Accountability、Fairness、Complianceが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“的他的法律、、技术者倫理”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Engineer Ethics","Guideline","Accountability","Fairness","Compliance"],"examFocusJa":"「その他の法律・ガイドライン・技術者倫理」の設問では、「技術者倫理」「ガイドライン」「説明責任」「公正性」「社会的影響」「法令遵守」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、個別法律の罰則問題の説明と混ぜないことが判断線です。","examFocusZh":"看到「他法律・・技術者倫理」相关题时，先抓技术者伦理、指南、说明责任、公正性、社会影响、合规是判断词。再判断题目问对象、责任、流程还是效果，并排除具体法律处罚题。","commonMistakeJa":"「その他の法律・ガイドライン・技術者倫理」を個別法律の罰則問題と混同すると誤答します。特に法律に違反しなければ倫理上も常に問題ないと考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「他法律・・技術者倫理」和具体法律处罚题混淆，尤其是误以为不违法就一定没有伦理问题。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":294,"pdfPageEnd":296,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-3 その他の法律・ガイドライン・技術者倫理","anchorTermsJa":["その他の法律","ガイドライン","技術者倫理"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、その他の法律・ガイドライン・技術者倫理が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「技術者倫理」「ガイドライン」「説明責任」「公正性」「社会的影響」「法令遵守」が判断線です。その語が出たら、まず理解工程师在法律、指南、伦理和社会责任之间的判断边界という意味に対応する日本語条件を探します。合わない場合は、個別法律の罰則問題を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“的他的法律、、技术者倫理”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Engineer Ethics","Guideline","Accountability","Fairness","Compliance"],"examFocusJa":"その他の法律・ガイドライン・技術者倫理の見分け方は、「技術者倫理」「ガイドライン」「説明責任」「公正性」「社会的影響」「法令遵守」が判断線ですを文章中から拾い、個別法律の罰則問題ではなくその他の法律・ガイドライン・技術者倫理を答えるべき条件かを確認することです。","examFocusZh":"其他法律、指南与技术者伦理的判断线索是技术者伦理、指南、说明责任、公正性、社会影响、合规是判断词，同时确认题干要求的是否是「他法律・・技術者倫理」，而不是具体法律处罚题。","commonMistakeJa":"その他の法律・ガイドライン・技術者倫理ではなく個別法律の罰則問題の説明を選ぶ誤りに注意します。原因は、法律に違反しなければ倫理上も常に問題ないと考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「他法律・・技術者倫理」（其他法律、指南与技术者伦理）和具体法律处罚题混淆。错误通常来自误以为不违法就一定没有伦理问题，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":294,"pdfPageEnd":296,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-3 その他の法律・ガイドライン・技術者倫理","anchorTermsJa":["その他の法律","ガイドライン","技術者倫理"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Engineer Ethics","termZh":"Engineer Ethics","english":"Engineer Ethics","definitionZh":"Engineer Ethics是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Engineer Ethicsに関する基本概念。","examCueZh":"题干出现Engineer Ethics及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Guideline","termZh":"Guideline","english":"Guideline","definitionZh":"Guideline是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Guidelineに関する基本概念。","examCueZh":"题干出现Guideline及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Accountability","termZh":"Accountability","english":"Accountability","definitionZh":"Accountability是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Accountabilityに関する基本概念。","examCueZh":"题干出现Accountability及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Fairness","termZh":"Fairness","english":"Fairness","definitionZh":"Fairness是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Fairnessに関する基本概念。","examCueZh":"题干出现Fairness及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Compliance","termZh":"Compliance","english":"Compliance","definitionZh":"Compliance是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Complianceに関する基本概念。","examCueZh":"题干出现Compliance及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"その他の法律・ガイドライン・技術者倫理と個別法律の罰則問題を混同する","trapZh":"把其他法律、指南与技术者伦理和具体法律处罚题混为一谈。"},{"trapJa":"法律に違反しなければ倫理上も常に問題ないと考える","trapZh":"误以为不违法就一定没有伦理问题。要写清错在哪里。"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":294,"pdfPageEnd":296,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-3 その他の法律・ガイドライン・技術者倫理","anchorTermsJa":["その他の法律","ガイドライン","技術者倫理"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握的他的法律、、技术者倫理的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。","goalJa":"問題文の条件を読み取り、「その他の法律・ガイドライン・技術者倫理」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"的他的法律、、技术者倫理：从业务问题出发的课堂讲解","headingJa":"5-2-3 その他の法律・ガイドライン・技術者倫理","bodyZh":"的他的法律、、技术者倫理不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Engineer Ethics、Guideline、Accountability、Fairness，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待的他的法律、、技术者倫理","bodyZh":"对企业而言，的他的法律、、技术者倫理直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“的他的法律、、技术者倫理”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Engineer Ethics、Guideline、Accountability、Fairness是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐的他的法律、、技术者倫理对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查的他的法律、、技术者倫理：问最恰当说明、最优先控制或易混淆概念。关键词多与Engineer Ethics、Guideline、Accountability、Fairness相关。","keywords":["Engineer Ethics","Guideline","Accountability","Fairness","Compliance"]},"examCues":[{"cueZh":"题干出现Engineer Ethics及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。的他的法律、、技术者倫理的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"的他的法律、、技术者倫理三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推的他的法律、、技术者倫理控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“的他的法律、、技术者倫理”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-2-4","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":10,"nativeSectionId":"5-2-4","titleJa":"5-2-4 標準化関連","titleZh":"标准化関連","overviewJa":"標準化関連は、SG標準化分野で標準化関連では、ISO、JIS、国際標準、業界標準、情報セキュリティや品質の基準を扱います。標準は互換性、品質、信頼性を高めるための共通ルールであり、法律や個別契約とは区別します。PDF 297-298ページの「標準化関連」を定位語に、試験では「ISO」「JIS」「国際標準」「業界標準」「互換性」「品質」が判断線です。法律・ガイドラインや技術者倫理との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"标准化相关用于理解 ISO、JIS、国际标准和行业标准如何提高互换性与安全管理质量。本单元依据 PDF 297-298 页的「標準化関連」定位，重点理解：标准化相关内容包括 ISO、JIS、国际标准、行业标准、安全和质量基准。标准是提高兼容性、质量和可靠性的共同规则，要和法律、个别合同区分。考试常用ISO、JIS、国际标准、行业标准、兼容性、质量是判断词来换说法；同时要和法律指南或技术者伦理区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「標準化関連」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“标准化関連”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"標準化関連を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。標準化関連では、ISO、JIS、国際標準、業界標準、情報セキュリティや品質の基準を扱います。標準は互換性、品質、信頼性を高めるための共通ルールであり、法律や個別契約とは区別します。この関係を押さえると、標準化関連は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではISO、JIS、International Standard、Compatibility、Qualityが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“标准化関連”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。若讲解停留在定义层，遇到案例题仍会失分。","englishTerms":["ISO","JIS","International Standard","Compatibility","Quality"],"examFocusJa":"「標準化関連」の設問では、「ISO」「JIS」「国際標準」「業界標準」「互換性」「品質」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、法律・ガイドラインや技術者倫理の説明と混ぜないことが判断線です。","examFocusZh":"看到「標準化関連」相关题时，先抓ISO、JIS、国际标准、行业标准、兼容性、质量是判断词。再判断题目问对象、责任、流程还是效果，并排除法律指南或技术者伦理。","commonMistakeJa":"「標準化関連」を法律・ガイドラインや技術者倫理と混同すると誤答します。特に標準をすべて法的強制力のある規制と考える場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「標準化関連」和法律指南或技术者伦理混淆，尤其是把所有标准都误认为具有法律强制力。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":297,"pdfPageEnd":298,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-4 標準化関連","anchorTermsJa":["標準化関連"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、標準化関連が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「ISO」「JIS」「国際標準」「業界標準」「互換性」「品質」が判断線です。その語が出たら、まず理解 ISO、JIS、国际标准和行业标准如何提高互换性与安全管理质量という意味に対応する日本語条件を探します。合わない場合は、法律・ガイドラインや技術者倫理を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“标准化関連”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["ISO","JIS","International Standard","Compatibility","Quality"],"examFocusJa":"標準化関連の見分け方は、「ISO」「JIS」「国際標準」「業界標準」「互換性」「品質」が判断線ですを文章中から拾い、法律・ガイドラインや技術者倫理ではなく標準化関連を答えるべき条件かを確認することです。","examFocusZh":"标准化相关的判断线索是ISO、JIS、国际标准、行业标准、兼容性、质量是判断词，同时确认题干要求的是否是「標準化関連」，而不是法律指南或技术者伦理。","commonMistakeJa":"標準化関連ではなく法律・ガイドラインや技術者倫理の説明を選ぶ誤りに注意します。原因は、標準をすべて法的強制力のある規制と考えるときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「標準化関連」（标准化相关）和法律指南或技术者伦理混淆。错误通常来自把所有标准都误认为具有法律强制力，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":297,"pdfPageEnd":298,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-4 標準化関連","anchorTermsJa":["標準化関連"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"ISO","termZh":"ISO","english":"ISO","definitionZh":"ISO是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"ISOに関する基本概念。","examCueZh":"题干出现ISO及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"JIS","termZh":"JIS","english":"JIS","definitionZh":"JIS是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"JISに関する基本概念。","examCueZh":"题干出现JIS及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"International Standard","termZh":"International Standard","english":"International Standard","definitionZh":"International Standard是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"International Standardに関する基本概念。","examCueZh":"题干出现International Standard及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Compatibility","termZh":"Compatibility","english":"Compatibility","definitionZh":"Compatibility是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Compatibilityに関する基本概念。","examCueZh":"题干出现Compatibility及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Quality","termZh":"Quality","english":"Quality","definitionZh":"Quality是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Qualityに関する基本概念。","examCueZh":"题干出现Quality及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"標準化関連と法律・ガイドラインや技術者倫理を混同する","trapZh":"把标准化相关和法律指南或技术者伦理混为一谈。"},{"trapJa":"標準をすべて法的強制力のある規制と考える","trapZh":"把所有标准都误认为具有法律强制力"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":297,"pdfPageEnd":298,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-4 標準化関連","anchorTermsJa":["標準化関連"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握标准化関連的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。目标要可检查。","goalJa":"問題文の条件を読み取り、「標準化関連」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"标准化関連：从业务问题出发的课堂讲解","headingJa":"5-2-4 標準化関連","bodyZh":"标准化関連不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括ISO、JIS、International Standard、Compatibility，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待标准化関連","bodyZh":"对企业而言，标准化関連直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“标准化関連”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查ISO、JIS、International Standard、Compatibility是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐标准化関連对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"IPA 常以短场景或条件描述考查标准化関連：问最恰当说明、最优先控制或易混淆概念。关键词多与ISO、JIS、International Standard、Compatibility相关。","keywords":["ISO","JIS","International Standard","Compatibility","Quality"]},"examCues":[{"cueZh":"题干出现ISO及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。标准化関連的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"标准化関連三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推标准化関連控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“标准化関連”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true},{"id":"sg-5-2-5","exam":"sg","chapterId":"sg-ch05","topicId":"strategy","order":11,"nativeSectionId":"5-2-5","titleJa":"5-2-5 演習問題","titleZh":"练习题","overviewJa":"演習問題は、SG演習分野で演習問題では、権利保護、契約関係、倫理判断、標準化の目的が混在します。保護対象、義務を負う主体、判断基準が何かを分けます。PDF 299-302ページの「演習問題」を定位語に、試験では「演習問題」「知的財産」「契約」「倫理」「標準化」「権利」が判断線です。セキュリティ対策技術問題との違いを押さえると、SGの事例問題でも条件から判断できます。","overviewZh":"法务与标准化演习问题用于检查知识产权、劳动交易、伦理、标准化的适用对象是否能区分。本单元依据 PDF 299-302 页的「演習問題」定位，重点理解：本节演习把知识产权、劳动交易、伦理和标准化混在一起考。要区分保护对象、承担义务的主体和使用的判断基准。考试常用演习问题、知识产权、合同、伦理、标准化、权利是判断词来换说法；同时要和安全技术对策题区分。学习重点是建立可执行判断：对象、风险、控制、验证四步闭环。","learningGoalJa":"問題文の条件を読み取り、「演習問題」に関する選択肢を根拠を持って判定できるようにする。","learningGoalZh":"能根据题干条件判断“练习题”相关选项，并说清楚判断依据。","sections":[{"headingJa":"仕組みと役割","headingZh":"机制与作用","explanationJa":"演習問題を学ぶときは、対策、法務、監査、サービス、又はプロジェクト管理のどこに位置付く単元なのかを先に決めます。演習問題では、権利保護、契約関係、倫理判断、標準化の目的が混在します。保護対象、義務を負う主体、判断基準が何かを分けます。この関係を押さえると、演習問題は単なる用語ではなく、SGの事例文で責任、手順、対策を結び付ける判断軸になります。英語表記ではExercise、Intellectual Property、Contract、Ethics、Standardが出やすいため、略語と役割を対応させます。","explanationZh":"机制与作用要围绕“练习题”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。若讲解停留在定义层，遇到案例题仍会失分。","englishTerms":["Exercise","Intellectual Property","Contract","Ethics","Standard"],"examFocusJa":"「演習問題」の設問では、「演習問題」「知的財産」「契約」「倫理」「標準化」「権利」が判断線です。まず対象、責任、手順、効果のどれを問うているかを確認し、セキュリティ対策技術問題の説明と混ぜないことが判断線です。","examFocusZh":"看到「演習問題」相关题时，先抓演习问题、知识产权、合同、伦理、标准化、权利是判断词。再判断题目问对象、责任、流程还是效果，并排除安全技术对策题。","commonMistakeJa":"「演習問題」をセキュリティ対策技術問題と混同すると誤答します。特に権利、契約、標準の目的を同じものとして扱う場合、事例文の責任、対象、手順の対応関係を読み落とします。","commonMistakeZh":"常见错误是把「演習問題」和安全技术对策题混淆，尤其是把权利、合同和标准的目的混为一谈。要回到案例里的责任主体、对象和流程。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":299,"pdfPageEnd":302,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-5 演習問題","anchorTermsJa":["演習問題"],"verificationStatus":"verified"}]},{"headingJa":"事例問題での切り分け","headingZh":"案例题中的区分方法","explanationJa":"SGでは、演習問題が単独の定義ではなく、事故対応、法令遵守、監査証拠、サービス運用、又はプロジェクト条件の文脈で出されます。「演習問題」「知的財産」「契約」「倫理」「標準化」「権利」が判断線です。その語が出たら、まず检查知识产权、劳动交易、伦理、标准化的适用对象是否能区分という意味に対応する日本語条件を探します。合わない場合は、セキュリティ対策技術問題を選ばせるひっかけである可能性があります。","explanationZh":"案例题中的区分方法要围绕“练习题”讲清机制、适用边界与验证方式。先说明它解决什么业务问题，再说明常见失败模式，最后给出可检查的落地动作。课堂中避免只堆术语，要把每个术语对应到职责、系统位置和事故后果。","englishTerms":["Exercise","Intellectual Property","Contract","Ethics","Standard"],"examFocusJa":"演習問題の見分け方は、「演習問題」「知的財産」「契約」「倫理」「標準化」「権利」が判断線ですを文章中から拾い、セキュリティ対策技術問題ではなく演習問題を答えるべき条件かを確認することです。","examFocusZh":"法务与标准化演习问题的判断线索是演习问题、知识产权、合同、伦理、标准化、权利是判断词，同时确认题干要求的是否是「演習問題」，而不是安全技术对策题。","commonMistakeJa":"演習問題ではなくセキュリティ対策技術問題の説明を選ぶ誤りに注意します。原因は、権利、契約、標準の目的を同じものとして扱うときに、目的、対象、発生タイミングの違いを読み落とすことです。","commonMistakeZh":"不要误把「演習問題」（法务与标准化演习问题）和安全技术对策题混淆。错误通常来自把权利、合同和标准的目的混为一谈，本质是漏读目的、对象或发生时机的差别。","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":299,"pdfPageEnd":302,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-5 演習問題","anchorTermsJa":["演習問題"],"verificationStatus":"verified"}]}],"keyTerms":[{"termJa":"Exercise","termZh":"Exercise","english":"Exercise","definitionZh":"Exercise是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Exerciseに関する基本概念。","examCueZh":"题干出现Exercise及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Intellectual Property","termZh":"Intellectual Property","english":"Intellectual Property","definitionZh":"Intellectual Property是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Intellectual Propertyに関する基本概念。","examCueZh":"题干出现Intellectual Property及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Contract","termZh":"Contract","english":"Contract","definitionZh":"Contract是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Contractに関する基本概念。","examCueZh":"题干出现Contract及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Ethics","termZh":"Ethics","english":"Ethics","definitionZh":"Ethics是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Ethicsに関する基本概念。","examCueZh":"题干出现Ethics及相关约束时，检查是否真正命中其定义与适用条件。"},{"termJa":"Standard","termZh":"Standard","english":"Standard","definitionZh":"Standard是与本单元主题相关的关键概念，用于说明控制对象、风险路径或验证方式。","definitionJa":"Standardに関する基本概念。","examCueZh":"题干出现Standard及相关约束时，检查是否真正命中其定义与适用条件。"}],"commonTraps":[{"trapJa":"演習問題とセキュリティ対策技術問題を混同する","trapZh":"把法务与标准化演习问题和安全技术对策题混为一谈。"},{"trapJa":"権利、契約、標準の目的を同じものとして扱う","trapZh":"把权利、合同和标准的目的混为一谈"}],"relatedQuestionIds":[],"practiceStatus":"no_existing_course_question","sourceRefs":[{"sourceId":"sg_security_textbook","pdfPageStart":299,"pdfPageEnd":302,"printedPageStart":null,"printedPageEnd":null,"headingJa":"5-2-5 演習問題","anchorTermsJa":["演習問題"],"verificationStatus":"verified"}],"sourceStatus":"verified","translationStatus":"reviewed","learningExperience":{"knowledgeStatus":"textbook_reconstructed_v1","reconstructedAt":"2026-07-11","goalZh":"掌握练习题的课堂讲法：概念、业务意义、案例路径、易混对比与考试映射。目标要可检查。","goalJa":"問題文の条件を読み取り、「演習問題」に関する選択肢を根拠を持って判定できるようにする。","coreConcept":{"headingZh":"练习题：从业务问题出发的课堂讲解","headingJa":"5-2-5 演習問題","bodyZh":"练习题不是孤立名词，而是法务与合规里用来保护业务连续性与可信度的关键能力。课堂讲解要先说明它解决什么问题、在网络安全、隐私保护、非法访问与知识产权边界中扮演什么角色，再说明如果不做会出现违法采集、越权访问、合同责任不清、监管处罚。学习时围绕“对象是谁、风险从哪来、控制怎么落地、如何验证有效”四条线展开，避免只背定义。本单元高频术语包括Exercise、Intellectual Property、Contract、Ethics，要把术语对应到职责与场景，而不是停留在翻译。"},"whyImportant":{"headingZh":"为什么企业必须认真对待练习题","bodyZh":"对企业而言，练习题直接关系到客户信任、交易正确性、系统可运营性和事故损失控制。真实组织会用预算、岗位职责和复盘机制推动这项能力，而不是等事故发生后再补救。考试反复出现，是因为它对应日常运营中的高频决策：先保什么、先拦什么、先恢复什么。"},"prerequisiteConcepts":[{"labelZh":"保护对象","bodyZh":"先确认本单元保护的信息资产、系统组件或业务流程是什么，对象不清则对策必然发散。"},{"labelZh":"法务与合规上下文","bodyZh":"把它放在网络安全、隐私保护、非法访问与知识产权边界整体中理解，避免与相邻概念抢同一解释。"},{"labelZh":"验证方式","bodyZh":"任何控制都要回答如何检查有效：日志、指标、演练或审计证据。"}],"caseBreakdown":[{"labelZh":"业务场景","bodyZh":"某企业在日常运营中遇到与“练习题”相关的异常：系统告警、流程受阻或客户投诉上升，团队需要快速判断问题属于哪一类控制缺口。"},{"labelZh":"拆解判断","bodyZh":"先定位对象与影响路径，再判断是预防不足、检测缺失还是恢复准备不够；同时检查Exercise、Intellectual Property、Contract、Ethics是否被正确配置和执行。"},{"labelZh":"错误动作","bodyZh":"常见错误是只加设备或只发通知，却不改职责、流程和验证方式，结果风险表面缓解、实质仍在。"},{"labelZh":"正确路径","bodyZh":"按“止损→查清→加固→验证”推进：先控制影响面，再补齐练习题对应控制，最后用演练或检查确认可重复生效。"}],"examPattern":{"headingZh":"IPA 常见出法","bodyZh":"综合题会把练习题放进长案例，要求先读条件再选对策。干扰项常给出“正确术语但不符合当前情境”的选项。做题时先标注对象、影响、约束条件，再回看选项。","keywords":["Exercise","Intellectual Property","Contract","Ethics","Standard"]},"examCues":[{"cueZh":"题干出现Exercise及相关约束时，优先回到本单元控制目标。"},{"cueZh":"先判断损失形态与责任边界，再选择技术或管理手段。"},{"cueZh":"选项若无法解释题干条件，即使术语正确也应排除。"}],"mistakeComparisons":[{"aZh":"法律义务","bZh":"企业内规","bodyZh":"法律义务与企业内规常被混用：前者更偏目标约束与组织安排，后者更偏落地动作与执行细节。题干会通过场景告诉你当前考哪一侧。"},{"aZh":"手段正确","bZh":"情境匹配","bodyZh":"很多干扰项在一般意义上正确，但不符合当前业务情境。练习题的得分点是匹配，而不是堆砌安全词汇。"}],"memoryTips":[{"tipZh":"练习题三问：保谁？怕啥？怎么验？"},{"tipZh":"先场景后术语：用业务损失反推练习题控制。"}],"quizMapping":{"relatedQuestionIds":[],"explanationZh":"本单元暂无已验证关联题，保持为空，不伪造题号。后续接入题库时应映射到“练习题”的条件判断类题目。"}},"knowledgeReconstructionStatus":"chapter5_textbook_v1","goldenBaseline":true}]};
